import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbSPARQL11ComplianceRegressionTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void bindValueRemainsInScopeForFollowingFilter(@TempDir File dataDir) {
		IRI p = VF.createIRI("http://example.org/p");
		IRI s1 = VF.createIRI("http://example.org/s1");
		IRI s4 = VF.createIRI("http://example.org/s4");

		SailRepository repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc")));
		try {
			try (var connection = repository.getConnection()) {
				connection.add(s1, p, VF.createLiteral(1));
				connection.add(s4, p, VF.createLiteral(4));

				String query = """
						PREFIX : <http://example.org/>
						SELECT ?s ?v ?z {
						  BIND(4 AS ?z)
						  ?s :p ?v .
						  FILTER(?v = ?z)
						}
						""";
				List<Value> subjects = new ArrayList<>();
				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					while (result.hasNext()) {
						subjects.add(result.next().getValue("s"));
					}
				}

				assertEquals(List.of(s4), subjects, () -> explainOptimized(connection, query));
			}
		} finally {
			repository.shutDown();
		}
	}

	@Test
	void namedGraphZeroLengthPathDoesNotRebindGraphVariable(@TempDir File dataDir) {
		IRI graph = VF.createIRI("urn:graph:ng-01");
		IRI a = VF.createIRI("http://www.example.org/a");
		IRI b = VF.createIRI("http://www.example.org/b");
		IRI p1 = VF.createIRI("http://www.example.org/p1");

		SailRepository repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc")));
		try {
			try (var connection = repository.getConnection()) {
				connection.add(a, p1, b, graph);

				String query = """
						PREFIX : <http://www.example.org/>
						SELECT ?t WHERE {
						  GRAPH ?g {
						    ?s :p1* ?t
						  }
						  FILTER (?g = <urn:graph:ng-01>)
						}
						""";
				List<Value> targets = new ArrayList<>();
				try {
					try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
						while (result.hasNext()) {
							targets.add(result.next().getValue("t"));
						}
					}
				} catch (AssertionError error) {
					AssertionError failure = new AssertionError(explainOptimized(connection, query));
					failure.initCause(error);
					throw failure;
				}

				assertEquals(1, Collections.frequency(targets, a));
				assertEquals(2, Collections.frequency(targets, b));
				assertEquals(3, targets.size());
			}
		} finally {
			repository.shutDown();
		}
	}

	private static String explainOptimized(org.eclipse.rdf4j.repository.RepositoryConnection connection,
			String query) {
		return connection.prepareTupleQuery(query)
				.explain(Explanation.Level.Optimized)
				.toString();
	}
}
